def element_to_dict(element) -> dict:
    """
    Helper function to convert a parsed XML element tree to a Python dictionary.
    """
    result = {
        "tag": element.tag,
        "attributes": dict(element.attrib),
        "text": (element.text or "").strip(),
        "children": [],
    }
    for child in element:
        result["children"].append(element_to_dict(child))
    return result


